SELECT percentage_held, SUM(transaction_amount) AS total_amount
FROM shareholdings
GROUP BY percentage_held;

SELECT COUNT(*) AS active_subsidiaries_count
FROM subsidiaries
WHERE status = 'active';

SELECT ceo AS SubsidiaryCEO, percentage_held AS PercentageHeld, registration_date AS RegistrationDate
FROM subsidiaries
WHERE status = 'active';
